1	/**
2	 * Sovereign Systems Spiral — Canvas Renderer
3	 *
4	 * Vanilla Canvas API implementation with 2D Perlin noise for organic orbital motion.
5	 * No dependencies. Targets 60fps with 4 pillar nodes, orbital arcs, and a logarithmic
6	 * spiral line. Desktop only — mobile gets SpiralFallback.astro (CSS-only).
7	 */
8	
9	// ---------------------------------------------------------------------------
10	// Types
11	// ---------------------------------------------------------------------------
12	
13	interface PillarData {
14	  name: string;
15	  slug: string;
16	  emoji: string;
17	  tagline: string;
18	  color: string;
19	  url: string;
20	  status: 'live' | 'coming-soon';
21	  order: number;
22	}
23	
24	// ---------------------------------------------------------------------------
25	// 2D Perlin Noise (minimal implementation)
26	// ---------------------------------------------------------------------------
27	
28	const PERM = new Uint8Array(512);
29	const GRAD = [
30	  [1, 1], [-1, 1], [1, -1], [-1, -1],
31	  [1, 0], [-1, 0], [0, 1], [0, -1],
32	];
33	
34	function initNoise(): void {
35	  const p = new Uint8Array(256);
36	  for (let i = 0; i < 256; i++) p[i] = i;
37	  for (let i = 255; i > 0; i--) {
38	    const j = Math.floor(Math.random() * (i + 1));
39	    [p[i], p[j]] = [p[j], p[i]];
40	  }
41	  for (let i = 0; i < 512; i++) PERM[i] = p[i & 255];
42	}
43	
44	function fade(t: number): number {
45	  return t * t * t * (t * (t * 6 - 15) + 10);
46	}
47	
48	function lerp(a: number, b: number, t: number): number {
49	  return a + (b - a) * t;
50	}
51	
52	function dot2(g: number[], x: number, y: number): number {
53	  return g[0] * x + g[1] * y;
54	}
55	
56	function noise2d(x: number, y: number): number {
57	  const xi = Math.floor(x) & 255;
58	  const yi = Math.floor(y) & 255;
59	  const xf = x - Math.floor(x);
60	  const yf = y - Math.floor(y);
61	  const u = fade(xf);
62	  const v = fade(yf);
63	
64	  const aa = PERM[PERM[xi] + yi] & 7;
65	  const ab = PERM[PERM[xi] + yi + 1] & 7;
66	  const ba = PERM[PERM[xi + 1] + yi] & 7;
67	  const bb = PERM[PERM[xi + 1] + yi + 1] & 7;
68	
69	  return lerp(
70	    lerp(dot2(GRAD[aa], xf, yf), dot2(GRAD[ba], xf - 1, yf), u),
71	    lerp(dot2(GRAD[ab], xf, yf - 1), dot2(GRAD[bb], xf - 1, yf - 1), u),
72	    v,
73	  );
74	}
75	
76	// ---------------------------------------------------------------------------
77	// Spiral Renderer
78	// ---------------------------------------------------------------------------
79	
80	const BASE_ROTATION_SPEED = 0.001;
81	const NODE_RADIUS = 26;
82	const HIT_RADIUS = 30;
83	const HOVER_SCALE = 1.15;
84	const LABEL_FONT = '13px Inter, system-ui, sans-serif';
85	const SUB_LABEL_FONT = '10px Inter, system-ui, sans-serif';
86	const CENTER_LABEL_FONT = '600 14px Inter, system-ui, sans-serif';
87	const EMOJI_FONT_SIZE = 22;
88	const ORBITAL_RADIUS_FACTORS = [0.6, 0.75, 0.9, 1.05];
89	
90	interface NodeState {
91	  x: number;
92	  y: number;
93	  currentScale: number;
94	  hovered: boolean;
95	}
96	
97	export function initSpiral(
98	  canvas: HTMLCanvasElement,
99	  pillars: PillarData[],
100	): () => void {
101	  const ctx = canvas.getContext('2d')!;
102	  let width = 0;
103	  let height = 0;
104	  let dpr = 1;
105	  let baseRadius = 0;
106	  let animFrame = 0;
107	  let globalAngle = 0;
108	  let mouseX = -9999;
109	  let mouseY = -9999;
110	
111	  initNoise();
112	
113	  const nodeStates: NodeState[] = pillars.map(() => ({
114	    x: 0,
115	    y: 0,
116	    currentScale: 1,
117	    hovered: false,
118	  }));
119	
120	  // --- Resize handler ---
121	
122	  function resize(): void {
123	    const rect = canvas.getBoundingClientRect();
124	    dpr = window.devicePixelRatio || 1;
125	    width = rect.width;
126	    height = rect.height;
127	    canvas.width = width * dpr;
128	    canvas.height = height * dpr;
129	    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
130	    baseRadius = Math.min(width, height) * 0.34;
131	  }
132	
133	  // --- Hit detection ---
134	
135	  function updateMouse(e: MouseEvent): void {
136	    const rect = canvas.getBoundingClientRect();
137	    mouseX = e.clientX - rect.left;
138	    mouseY = e.clientY - rect.top;
139	  }
140	
141	  function handleClick(): void {
142	    for (let i = 0; i < pillars.length; i++) {
143	      if (nodeStates[i].hovered) {
144	        window.location.href = pillars[i].url;
145	        return;
146	      }
147	    }
148	  }
149	
150	  // --- Drawing primitives ---
151	
152	  function hexToRgba(hex: string, alpha: number): string {
153	    const r = parseInt(hex.slice(1, 3), 16);
154	    const g = parseInt(hex.slice(3, 5), 16);
155	    const b = parseInt(hex.slice(5, 7), 16);
156	    return `rgba(${r},${g},${b},${alpha})`;
157	  }
158	
159	  // --- Draw functions ---
160	
161	  function drawOrbitalPaths(cx: number, cy: number): void {
162	    ctx.save();
163	    ctx.setLineDash([2, 6]);
164	    ctx.lineWidth = 1;
165	    for (let i = 0; i < pillars.length; i++) {
166	      const r = baseRadius * ORBITAL_RADIUS_FACTORS[i];
167	      ctx.strokeStyle = hexToRgba(pillars[i].color, 0.15);
168	      ctx.beginPath();
169	      ctx.arc(cx, cy, r, 0, Math.PI * 2);
170	      ctx.stroke();
171	    }
172	    ctx.restore();
173	  }
174	
175	  function drawLogarithmicSpiral(cx: number, cy: number, time: number): void {
176	    ctx.save();
177	    ctx.strokeStyle = hexToRgba('#c9a96e', 0.12);
178	    ctx.lineWidth = 1;
179	    ctx.beginPath();
180	    const a = 4;
181	    const b = 0.18;
182	    const rotOffset = time * 0.0003;
183	    for (let theta = 0; theta < Math.PI * 8; theta += 0.05) {
184	      const r = a * Math.exp(b * theta);
185	      if (r > baseRadius * 1.2) break;
186	      const x = cx + r * Math.cos(theta + rotOffset);
187	      const y = cy + r * Math.sin(theta + rotOffset);
188	      if (theta === 0) ctx.moveTo(x, y);
189	      else ctx.lineTo(x, y);
190	    }
191	    ctx.stroke();
192	    ctx.restore();
193	  }
194	
195	  function drawCenterNode(cx: number, cy: number, time: number): void {
196	    const pulse = 0.7 + 0.3 * Math.sin(time * 0.002);
197	
198	    // Subtle glow
199	    ctx.save();
200	    ctx.globalAlpha = pulse * 0.15;
201	    ctx.fillStyle = '#119a9e';
202	    ctx.beginPath();
203	    ctx.arc(cx, cy, 18, 0, Math.PI * 2);
204	    ctx.fill();
205	    ctx.restore();
206	
207	    // Dot
208	    ctx.save();
209	    ctx.globalAlpha = pulse;
210	    ctx.fillStyle = '#e8e4df';
211	    ctx.beginPath();
212	    ctx.arc(cx, cy, 4, 0, Math.PI * 2);
213	    ctx.fill();
214	    ctx.restore();
215	
216	    // Label
217	    ctx.save();
218	    ctx.globalAlpha = pulse * 0.8;
219	    ctx.fillStyle = '#e8e4df';
220	    ctx.font = CENTER_LABEL_FONT;
221	    ctx.textAlign = 'center';
222	    ctx.textBaseline = 'top';
223	    ctx.fillText('SOVEREIGN SYSTEMS', cx, cy + 14);
224	    ctx.restore();
225	  }
226	
227	  function drawPillarNode(
228	    pillar: PillarData,
229	    state: NodeState,
230	    index: number,
231	    time: number,
232	  ): void {
233	    const isLive = pillar.status === 'live';
234	    const isHovered = state.hovered;
235	    const targetScale = isHovered ? HOVER_SCALE : 1;
236	    state.currentScale = lerp(state.currentScale, targetScale, 0.12);
237	    const scale = state.currentScale;
238	    const r = NODE_RADIUS * scale;
239	
240	    const baseAlpha = isLive ? 1 : 0.5;
241	    const hoverAlpha = isHovered ? 1 : baseAlpha;
242	
243	    ctx.save();
244	    ctx.translate(state.x, state.y);
245	
246	    // Fill
247	    ctx.fillStyle = hexToRgba(pillar.color, 0.12 * hoverAlpha);
248	    ctx.beginPath();
249	    ctx.arc(0, 0, r, 0, Math.PI * 2);
250	    ctx.fill();
251	
252	    // Stroke
253	    ctx.lineWidth = 2;
254	    if (!isLive) {
255	      ctx.setLineDash([4, 4]);
256	    }
257	    ctx.strokeStyle = hexToRgba(pillar.color, 0.8 * hoverAlpha);
258	    ctx.beginPath();
259	    ctx.arc(0, 0, r, 0, Math.PI * 2);
260	    ctx.stroke();
261	    ctx.setLineDash([]);
262	
263	    // Emoji
264	    ctx.font = `${Math.round(EMOJI_FONT_SIZE * scale)}px serif`;
265	    ctx.textAlign = 'center';
266	    ctx.textBaseline = 'middle';
267	    ctx.fillText(pillar.emoji, 0, -1);
268	
269	    // Name label
270	    ctx.fillStyle = hexToRgba('#e8e4df', isHovered ? 1 : 0.75 * baseAlpha);
271	    ctx.font = LABEL_FONT;
272	    ctx.textBaseline = 'top';
273	    ctx.fillText(pillar.name, 0, r + 8);
274	
275	    // "coming soon" sub-label
276	    if (!isLive) {
277	      ctx.fillStyle = hexToRgba('#8cc5d3', 0.6);
278	      ctx.font = SUB_LABEL_FONT;
279	      ctx.fillText('coming soon', 0, r + 24);
280	    }
281	
282	    ctx.restore();
283	  }
284	
285	  // --- Main draw loop ---
286	
287	  function draw(time: number): void {
288	    // Fill with opaque background to prevent ghost trails from translucent elements
289	    ctx.fillStyle = '#071e22';
290	    ctx.fillRect(0, 0, width, height);
291	
292	    const cx = width / 2;
293	    const cy = height / 2;
294	
295	    // Logarithmic spiral background line
296	    drawLogarithmicSpiral(cx, cy, time);
297	
298	    // Orbital paths
299	    drawOrbitalPaths(cx, cy);
300	
301	    // Advance global rotation
302	    globalAngle += BASE_ROTATION_SPEED;
303	
304	    // Pillar nodes
305	    let anyCursorHover = false;
306	    for (let i = 0; i < pillars.length; i++) {
307	      const orbitalR = baseRadius * ORBITAL_RADIUS_FACTORS[i];
308	      const angleOffset = (Math.PI * 2 * i) / pillars.length;
309	
310	      // Perlin wobble
311	      const noiseAngle = noise2d(i * 1.7, time * 0.0004) * 0.25;
312	      const noiseRadius = noise2d(i * 2.3 + 100, time * 0.0003) * 12;
313	
314	      // Slow down orbit for hovered node
315	      const speedMul = nodeStates[i].hovered ? 0.3 : 1;
316	      const angle = globalAngle * speedMul + angleOffset + noiseAngle;
317	      const r = orbitalR + noiseRadius;
318	
319	      const nx = cx + r * Math.cos(angle);
320	      const ny = cy + r * Math.sin(angle);
321	      nodeStates[i].x = nx;
322	      nodeStates[i].y = ny;
323	
324	      // Hit detection
325	      const dx = mouseX - nx;
326	      const dy = mouseY - ny;
327	      const dist = Math.sqrt(dx * dx + dy * dy);
328	      nodeStates[i].hovered = dist < HIT_RADIUS;
329	      if (nodeStates[i].hovered) anyCursorHover = true;
330	
331	      drawPillarNode(pillars[i], nodeStates[i], i, time);
332	    }
333	
334	    canvas.style.cursor = anyCursorHover ? 'pointer' : 'default';
335	
336	    // Center node
337	    drawCenterNode(cx, cy, time);
338	
339	    animFrame = requestAnimationFrame(draw);
340	  }
341	
342	  // --- Bootstrap ---
343	
344	  resize();
345	  animFrame = requestAnimationFrame(draw);
346	
347	  window.addEventListener('resize', resize);
348	  canvas.addEventListener('mousemove', updateMouse);
349	  canvas.addEventListener('click', handleClick);
350	
351	  // --- Cleanup ---
352	
353	  return function cleanup(): void {
354	    cancelAnimationFrame(animFrame);
355	    window.removeEventListener('resize', resize);
356	    canvas.removeEventListener('mousemove', updateMouse);
357	    canvas.removeEventListener('click', handleClick);
358	  };
359	}
