2	/**
3	 * SpiralIsland — Desktop canvas wrapper.
4	 *
5	 * Uses a module <script> so Vite bundles the dynamic import of spiral.ts.
6	 * Pillar data is passed via a data attribute on the canvas element.
7	 * Canvas container is hidden below md breakpoint via Tailwind.
8	 */
9	import { config } from '../../data/hub.config';
10	
11	const pillarsJson = JSON.stringify(config.pillars);
12	---
13	
14	<div class="relative w-full hidden md:block" style="height: 420px;">
15	  <canvas
16	    id="spiral-canvas"
17	    class="absolute inset-0 w-full h-full"
18	    data-pillars={pillarsJson}
19	  ></canvas>
20	</div>
21	
22	<script>
23	  // Guard against double-initialization (causes ghost echoes)
24	  const INIT_KEY = '__spiralCleanup';
25	
26	  function boot(): void {
27	    if (!window.matchMedia('(min-width: 768px)').matches) return;
28	
29	    const canvas = document.getElementById('spiral-canvas') as HTMLCanvasElement | null;
30	    if (!canvas) return;
31	
32	    // Kill any existing animation loop before starting a new one
33	    if ((window as any)[INIT_KEY]) {
34	      (window as any)[INIT_KEY]();
35	      (window as any)[INIT_KEY] = null;
36	    }
37	
38	    const raw = canvas.dataset.pillars;
39	    if (!raw) return;
40	
41	    import('./spiral.ts').then(({ initSpiral }) => {
42	      const pillars = JSON.parse(raw);
43	      const cleanup = initSpiral(canvas, pillars);
44	
45	      // Store cleanup so we can kill it if boot runs again
46	      (window as any)[INIT_KEY] = cleanup;
47	
48	      // Cleanup on Astro view transition
49	      document.addEventListener('astro:before-swap', () => {
50	        cleanup();
51	        (window as any)[INIT_KEY] = null;
52	      }, { once: true });
53	    });
54	  }
55	
56	  boot();
57	</script>
