2	import { config } from '../../data/hub.config';
3	
4	const { pillars } = config;
5	const delays = ['0s', '0.3s', '0.6s', '0.9s'];
6	---
7	
8	<div class="md:hidden px-6 py-8 flex flex-col items-center gap-4">
9	  {pillars.map((pillar, i) => {
10	    const isLive = pillar.status === 'live';
11	    const Tag = isLive ? 'a' : 'div';
12	    return (
13	      <Tag
14	        href={isLive ? pillar.url : undefined}
15	        class:list={[
16	          'spiral-card glass-card w-full max-w-sm flex items-center gap-4 p-5',
17	          !isLive && 'opacity-40 hover:transform-none hover:shadow-none',
18	        ]}
19	        style={`animation-delay: ${delays[i]};`}
20	      >
21	        <span class="text-3xl flex-shrink-0">{pillar.emoji}</span>
22	        <div>
23	          <p class="font-medium text-white/80 text-sm">{pillar.name}</p>
24	          <p class="text-white/30 text-xs mt-0.5">{pillar.tagline}</p>
25	          {!isLive && (
26	            <p class="text-white/20 text-[10px] mt-1 uppercase tracking-wider">coming soon</p>
27	          )}
28	        </div>
29	      </Tag>
30	    );
31	  })}
32	</div>
33	
34	<style>
35	  @keyframes float {
36	    0%, 100% { transform: translateY(0); }
37	    50%      { transform: translateY(-5px); }
38	  }
39	  .spiral-card {
40	    animation: float 3.5s ease-in-out infinite;
41	  }
42	</style>
